// LESSON: JavaFX Structure - Reference Page 2.
// You will learn: Create JavaFX nodes, events, scenes, and stages.
import javafx.application.Application;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class JavaFxStructureReference extends Application {
  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    // EXAMPLE 1: create nodes for the scene graph.
    Label label = new Label("Hello JavaFX");
    Button button = new Button("OK");
    VBox root = new VBox(8, label, button);
    // EXAMPLE 2: connect an event to a control.
    button.setOnAction(event -> label.setText("Clicked"));
    // EXAMPLE 3: create a scene and show it in a stage.
    Scene scene = new Scene(root, 300, 200);
    stage.setTitle("Structure");
    stage.setScene(scene);
    stage.show();
  }
}
